              theme: currentTheme,
              model: savedModel,
            }),
          },
          { type: "global" },
        );
      } catch (_) {}
    }

    // ── Quản lý mô hình cốt lõi (Bốn chế độ loại trừ và phân bổ chính xác) ──
    const ALL_MODEL_PROMPTS = [
      "✨ Gemini",
      "✨Gemini✨",
      "🎨 Claude",
      "🎨Claude🎨",
      "—\\✨思考模式（简）",
      "—\\✨思考模式（繁）",
      "—\\✨自由CoT",
      "—\\🎐思考模式",
      "—\\✴️思考模式",
      "✳️GLM Core",
      "🛑Core",
    ];

    function setModel(type) {
      if (!pdoc.querySelector("#completion_prompt_manager_list")) {
        toastr.warning("Vui lòng mở bảng cài đặt trước");
        return;
      }

      // Cập nhật và lưu tên mô hình đang kích hoạt
      savedModel = type;
      savePos();

      // Có giữ lại "Phồn" đã chọn hay không
      const useFan = isKeyOn("—\\✨思考模式（繁）");

      const turnOn = [];
      let corePrompt = "🛑Core";

      if (type === "gemini") {
        turnOn.push("✨Gemini✨", "✨ Gemini");
        turnOn.push(useFan ? "—\\✨思考模式（繁）" : "—\\✨思考模式（简）");
      } else if (type === "glm") {
        // Cấu hình cấu trúc độc quyền GLM
        turnOn.push("✨Gemini✨", "—\\✴️思考模式");
        corePrompt = "✳️GLM Core";
      } else if (type === "claude") {
        // Khắc 4.6
        turnOn.push("🎨Claude🎨", "🎨 Claude", "—\\🎐思考模式");
      } else if (type === "c45s") {
        turnOn.push("🎨Claude🎨", "✨ Gemini", "—\\🎐思考模式");
      } else if (type === "deepseek") {
        turnOn.push("✨Gemini✨", "✨ Gemini", "—\\🎐思考模式");
      }

      turnOn.push(corePrompt);

      // Xóa tuyệt đối các tùy chọn cốt lõi không liên quan, sau đó bật tùy chọn tương ứng
      ALL_MODEL_PROMPTS.forEach((kw) => {
        if (turnOn.includes(kw)) ensureOn(kw);
        else ensureOff(kw);
      });

      // Làm mới đèn báo UI
      const ids = {
        gemini: `${ID}-cot-gemini`,
        glm: `${ID}-cot-glm`,
        claude: `${ID}-cot-claude`,
        c45s: `${ID}-cot-c45s`,
        deepseek: `${ID}-cot-deepseek`,
      };
      Object.values(ids).forEach((id) => {
        pdoc.getElementById(id)?.classList.remove("is-on");
      });
      pdoc.getElementById(ids[type])?.classList.add("is-on");

      toastr.success(`Đã chuyển đổi chế độ mô hình: ${type.toUpperCase()}`);
    }

    pdoc.getElementById(`${ID}-cot-gemini`)?.addEventListener("click", () => setModel("gemini"));
    pdoc.getElementById(`${ID}-cot-glm`)?.addEventListener("click", () => setModel("glm"));
    pdoc.getElementById(`${ID}-cot-claude`)?.addEventListener("click", () => setModel("claude"));
    pdoc.getElementById(`${ID}-cot-c45s`)?.addEventListener("click", () => setModel("c45s"));
    pdoc.getElementById(`${ID}-cot-deepseek`)?.addEventListener("click", () => setModel("deepseek"));

    // ── Logic chuyển đổi chủ đề ──
    pdoc.querySelectorAll(".t-dot").forEach((dot) => {
      dot.addEventListener("click", (e) => {
        e.stopPropagation();
        const theme = dot.getAttribute("data-theme");
        shell.className = `menu-shell ${theme}`;
        pdoc.querySelectorAll(".t-dot").forEach((d) => {
          d.classList.remove("active");
        });
        dot.classList.add("active");
        currentTheme = theme;
        savePos();
      });
    });

    // ── Logic cốt lõi chọn một và công tắc ──
    let previousCotState = [];
    const cotKws = ["—\\✨思考模式（简）", "—\\✨思考模式（繁）", "—\\✨自由CoT", "—\\🎐思考模式"];

    const LINK_PAIRS = [
      { a: "📶加强世界书阅读", b: "📚// COT //世界书增强" },
      { a: "📚// COT //世界书增强", b: "📶加强世界书阅读" },
    ];
    function getLinkTarget(key) {
      for (const p of LINK_PAIRS) {
        if (p.a === key) return p.b;
      }
      return null;
    }

    const KAO_DA_KEY = "👊拷打（拷打克劳德）";
    const DA_ZONG_JIE_KEY = "💥大总结模式";
    const AI_DUI_HUA_KEY = "🤬AI对话（对线哈基米）";
    const CLAUDE_COT_KEY = "—\\🎐思考模式";

    pdoc.querySelectorAll(".toggle-btn").forEach((btn) => {
      btn.addEventListener("click", () => {
        if (!pdoc.querySelector("#completion_prompt_manager_list")) {
          toastr.warning("Vui lòng mở bảng cài đặt trước");
          return;
        }

        const key = resolveKey(btn);
        const kw = btn.getAttribute("data-kw");
        const groupName = btn.getAttribute("data-group");
        const isEdit = btn.getAttribute("data-edit") === "true";
        const isOn = btn.classList.contains("is-on");

        if (isOn) {
          ensureOff(key);
          btn.classList.remove("is-on");

          const linkTarget = getLinkTarget(key) || getLinkTarget(kw);
          if (linkTarget) syncToggle(linkTarget, false);

          if (kw === KAO_DA_KEY) {
            syncToggle(CLAUDE_COT_KEY, true);
          }

          if (kw === DA_ZONG_JIE_KEY) {
            previousCotState.forEach((ckw) => {
              syncToggle(ckw, true);
            });
            previousCotState = [];
            toastr.info("Đã thoát chế độ đại tổng kết, khôi phục module suy nghĩ");
          }
        } else {
          if (groupName) {
            pdoc.querySelectorAll(`.toggle-btn[data-group="${groupName}"]`).forEach((otherBtn) => {
              if (otherBtn !== btn && otherBtn.classList.contains("is-on")) {
                const otherKey = resolveKey(otherBtn);
                const otherKw = otherBtn.getAttribute("data-kw");
                ensureOff(otherKey);
                otherBtn.classList.remove("is-on");

                if (otherKw === DA_ZONG_JIE_KEY) {
                  previousCotState.forEach((ckw) => {
                    syncToggle(ckw, true);
                  });
                  previousCotState = [];
                }
                if (otherKw === KAO_DA_KEY) {
                  syncToggle(CLAUDE_COT_KEY, true);
                }
              }
            });

            if (groupName === "special-mode") {
              if (kw === AI_DUI_HUA_KEY) setModel("gemini");
              else if (kw === KAO_DA_KEY) setModel("claude");
            }
          }

          ensureOn(key);
          if (isEdit) {
            openEditModal(key);
          }
          btn.classList.add("is-on");

          const linkTarget = getLinkTarget(key) || getLinkTarget(kw);
          if (linkTarget) syncToggle(linkTarget, true);

          if (kw === KAO_DA_KEY) {
            syncToggle(CLAUDE_COT_KEY, false);
          }

          if (kw === DA_ZONG_JIE_KEY) {
            previousCotState = cotKws.filter((ckw) => isKeyOn(ckw));
            cotKws.forEach((ckw) => {
              syncToggle(ckw, false);
            });
            toastr.info("Đã vào chế độ đại tổng kết, tự động tắt module suy nghĩ");
          }
        }
      });
    });

    // ── Kiểm tra trạng thái khởi tạo ──
    function initDetectState() {
      if (!pdoc.querySelector("#completion_prompt_manager_list")) return;

      const on = (kw) => isKeyOn(kw);

      let currentModel = null;

      if (on("🎨Claude🎨") && on("✨ Gemini") && on("—\\🎐思考模式")) {
        currentModel = "c45s";
      } else if (on("✨Gemini✨") && on("✨ Gemini") && on("—\\🎐思考模式")) {
        currentModel = "deepseek";
      } else if (on("🎨Claude🎨") && on("🎨 Claude") && on("—\\🎐思考模式")) {
        currentModel = "claude";
      } else if (on("—\\✴️思考模式") && on("✨Gemini✨")) {
        currentModel = "glm";
      } else if (
        on("✨Gemini✨") &&
        on("✨ Gemini") &&
        (on("—\\✨思考模式（简）") || on("—\\✨思考模式（繁）") || on("—\\✨自由CoT"))
      ) {
        currentModel = savedModel === "glm" ? "glm" : "gemini";
      }

      if (currentModel) {
        const ids = {
          gemini: `${ID}-cot-gemini`,
          glm: `${ID}-cot-glm`,
          claude: `${ID}-cot-claude`,
          c45s: `${ID}-cot-c45s`,
          deepseek: `${ID}-cot-deepseek`,
        };
        Object.values(ids).forEach((id) => {
          pdoc.getElementById(id)?.classList.remove("is-on");
        });
        pdoc.getElementById(ids[currentModel])?.classList.add("is-on");
        savedModel = currentModel;
      }

      resolveButtonIds();

      pdoc.querySelectorAll(".toggle-btn").forEach((btn) => {
        const key = resolveKey(btn);
        btn.classList.toggle("is-on", isKeyOn(key));
      });
    }

    function buildNameIdMap() {
      const map = {};
      const list = pdoc.querySelector("#completion_prompt_manager_list") || pdoc;
      list.querySelectorAll("li[data-pm-identifier]").forEach((li) => {
        const id = li.getAttribute("data-pm-identifier");
        const name = li.querySelector("[data-pm-name]")?.getAttribute?.("data-pm-name") ?? "";
        if (name) map[name.trim()] = id;
      });
      return map;
    }

    function displayName(name) {
      let s = name;
      s = s.replace(/\/\/\s*COT\s*\/\//g, "COT ");
      s = s.replace(/^[^\p{L}\p{N}]*/gu, "");
      const atIdx = s.indexOf("@");
      if (atIdx > 0) s = s.substring(0, atIdx);
      return s.replace(/\s+/g, " ").trim() || name;
    }

    function resolveButtonIds() {
      const nameToId = buildNameIdMap();
      const idToName = buildIdNameMap();
      pdoc.querySelectorAll(".toggle-btn").forEach((btn) => {
        const existingId = btn.getAttribute("data-id");
        const kw = btn.getAttribute("data-kw");
        if (existingId) {
          const realName = idToName[existingId];
          if (realName && realName !== kw) {
            btn.setAttribute("data-kw", realName);
            const textEl = btn.querySelector(".menu-item-text");
            if (textEl) textEl.textContent = displayName(realName);
          }
        } else if (kw) {
          const foundId = nameToId[kw.trim()];
          if (foundId) {
            btn.setAttribute("data-id", foundId);
            const textEl = btn.querySelector(".menu-item-text");
            if (textEl) textEl.textContent = displayName(kw);
          }
        }
      });
    }

    // ── Đồng bộ ngược thao tác UI gốc (Phiên bản MutationObserver tuyệt đối đáng tin cậy) ──
    const reverseSyncObserver = new MutationObserver((mutations) => {
      let shouldUpdate = false;
      for (const m of mutations) {
        if (
          m.type === "attributes" &&
          m.attributeName === "class" &&
          m.target.tagName === "LI" &&
          m.target.hasAttribute("data-pm-identifier")
        ) {
          shouldUpdate = true;
          break;
        }
        if (m.type === "childList" && m.target.id === "completion_prompt_manager_list") {
          shouldUpdate = true;
          break;
        }
      }
      if (shouldUpdate) {
        clearTimeout(pwin._orbSyncTimer);
        pwin._orbSyncTimer = setTimeout(initDetectState, 80);
      }
    });

    function attachReverseObserver() {
      const list = pdoc.getElementById("completion_prompt_manager_list");
      if (list && !list.dataset.orbObserved) {
        reverseSyncObserver.observe(list, { attributes: true, subtree: true, childList: true, attributeFilter: ["class"] });
        list.dataset.orbObserved = "true";
      }
    }

    // Đánh chặn giai đoạn chụp, đối phó với khả năng chặn sự kiện và vẽ lại DOM của ST
    pdoc.addEventListener(
      "click",
      (e) => {
        attachReverseObserver();
        if (e.target.closest("#completion_prompt_manager_list") || e.target.closest(".drawer-content")) {
          clearTimeout(pwin._orbSyncTimer);
          pwin._orbSyncTimer = setTimeout(initDetectState, 150);
        }
      },
      true,
    );

    pdoc.addEventListener(
      "change",
      (e) => {
        if (e.target.closest(".drawer-content") || e.target.tagName === "SELECT") {
          clearTimeout(pwin._orbSyncTimer);
          pwin._orbSyncTimer = setTimeout(() => {
            attachReverseObserver();
            initDetectState();
          }, 400);
        }
      },
      true,
    );

    let initDone = false;
    function tryInitDetect() {
      if (initDone) return;
      if (pdoc.querySelector("#completion_prompt_manager_list")) {
        initDone = true;
        initDetectState();
        attachReverseObserver(); // 初始挂载监听
      }
    }
    // Cho chút thời gian đệm tải
    setTimeout(tryInitDetect, 1200);
    setTimeout(tryInitDetect, 2500);

    // ── Logic mở rộng vị trí UI ──
    function updateMenuDirection() {
      const orbX = parseInt(root.style.left, 10) || 0;
      const orbY = parseInt(root.style.top, 10) || 0;
      const menuH = 480;
      if (orbX < pwin.innerWidth / 2) {
        menu.style.left = "0";
        menu.style.right = "auto";
      } else {
        menu.style.left = "auto";
        menu.style.right = "0";
      }
      const spaceBelow = pwin.innerHeight - orbY - 60;
      if (spaceBelow < menuH && orbY > menuH / 2) {
        menu.style.top = "auto";
        menu.style.bottom = "52px";
        root.classList.add("open-up");
        menu.style.transformOrigin = orbX < pwin.innerWidth / 2 ? "bottom left" : "bottom right";
      } else {
        menu.style.top = "52px";
        menu.style.bottom = "auto";
        root.classList.remove("open-up");
        menu.style.transformOrigin = orbX < pwin.innerWidth / 2 ? "top left" : "top right";
      }
    }

    function toggle() {
      isOpen = !isOpen;
      if (isOpen) {
        updateMenuDirection();
        initDetectState();
        attachReverseObserver();
      } else {
        root.classList.remove("open-up");
      }
      root.classList.toggle("open", isOpen);
    }
    function close() {
      isOpen = true;
      toggle();
    }

    btnClose.addEventListener("click", (e) => {
      e.stopPropagation();
      close();
    });

    let drag = false,
      ox = 0,
      oy = 0,
      moved = false,
      dragMask = null;
    function createMask() {
      dragMask = parent.document.createElement("div");
      dragMask.style.cssText = "position:fixed;inset:0;z-index:2147483646;cursor:grabbing;background:transparent;";
      parent.document.body.appendChild(dragMask);
    }
    function removeMask() {
      dragMask?.remove();
      dragMask = null;
    }
    function startDrag(cx, cy) {
      drag = true;
      moved = false;
      const rect = root.getBoundingClientRect();
      ox = cx - rect.left;
      oy = cy - rect.top;
      root.style.transition = "none";
      createMask();
    }
    function moveDrag(cx, cy) {
      if (!drag) return;
      moved = true;
      root.style.left = `${Math.max(4, Math.min(cx - ox, pwin.innerWidth - 50))}px`;
      root.style.top = `${Math.max(4, Math.min(cy - oy, pwin.innerHeight - 50))}px`;
    }
    function endDrag() {
      if (!drag) return;
      drag = false;
      root.style.transition = "";
      removeMask();
      if (moved) savePos();
    }

    orb.addEventListener("mousedown", (e) => {
      startDrag(e.clientX, e.clientY);
      e.preventDefault();
    });
    head.addEventListener("mousedown", (e) => {
      if (e.target.id === `${ID}-close` || e.target.classList.contains("t-dot")) return;
      startDrag(e.clientX, e.clientY);
      e.preventDefault();
    });
    parent.document.addEventListener("mousemove", (e) => moveDrag(e.clientX, e.clientY));
    parent.document.addEventListener("mouseup", () => endDrag());

    orb.addEventListener("click", () => {
      if (moved) {
        moved = false;
        return;
      }
      toggle();
    });

    orb.addEventListener(
      "touchstart",
      (e) => {
        startDrag(e.touches[0].clientX, e.touches[0].clientY);
        e.stopPropagation();
      },
      { passive: true },
    );
    orb.addEventListener(
      "touchmove",
      (e) => {
        if (!drag) return;
        moveDrag(e.touches[0].clientX, e.touches[0].clientY);
      },
      { passive: true },
    );
    orb.addEventListener(
      "touchend",
      (e) => {
        const wasMoved = moved;
        endDrag();
        if (!wasMoved) toggle();
        e.stopPropagation();
        e.preventDefault();
      },
      { passive: false },
    );

    head.addEventListener(
      "touchstart",
      (e) => {
        if (e.target.id === `${ID}-close` || e.target.classList.contains("t-dot")) return;
        startDrag(e.touches[0].clientX, e.touches[0].clientY);
        e.stopPropagation();
      },
      { passive: true },
    );
    head.addEventListener(
      "touchmove",
      (e) => {
        if (!drag) return;
        moveDrag(e.touches[0].clientX, e.touches[0].clientY);
      },
      { passive: true },
    );
    head.addEventListener(
      "touchend",
      (e) => {
        endDrag();
        e.stopPropagation();
      },
      { passive: true },
    );

    window.addEventListener("pagehide", () => {
      pdoc.getElementById(ID)?.remove();
      pdoc.getElementById(`${ID}-style`)?.remove();
    });
    window.addEventListener("unload", () => {
      pdoc.getElementById(ID)?.remove();
      pdoc.getElementById(`${ID}-style`)?.remove();
    });
  }),
);

/*
