    transition: all 0.4s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
}

/* --- Lớp giữa bong bóng 3D: Kết cấu lập thể nhám bóng tối --- */
.mes_reasoning_header::before {
    content: '' !important;
    position: absolute !important;
    top: 0 !important; left: 0 !important; right: 0 !important; bottom: 0 !important;
    border-radius: 10px !important;
    z-index: -2 !important; 
    transition: all 0.4s ease !important;

    /* 🔥 Nâng cấp kết cấu: Thêm viền bán trong suốt 1px, giúp viền sắc nét hơn */
    border: 1px solid rgba(255, 255, 255, 0.05) !important;

    /* 🔥 Nâng cấp kết cấu: Xếp chồng nhiều lớp ánh sáng và bóng tối. Bóng đổ ngoài lơ lửng + Điểm nhấn phát sáng bên trong góc trên bên trái (vát góc) + Bóng tối bên trong góc dưới bên phải */
    box-shadow: 
        4px 4px 12px rgba(0, 0, 0, 0.4), 
