      const ext = file.name.split('.').pop()?.toLowerCase() || '';
      if (!FONT_EXT_FORMAT_MAP[ext]) { alert('Định dạng phông chữ không được hỗ trợ, vui lòng chọn .woff2 / .woff / .ttf / .otf'); return; }
