function injectWandMenuItem() {
  // Thử lấy document trang chính của quán rượu (script có thể chạy trong iframe)
  let doc;
  const candidates = [];
  try { if (window.top && window.top.document) candidates.push(window.top.document); } catch (_) {}
  try { if (window.parent && window.parent.document && window.parent.document !== document) candidates.push(window.parent.document); } catch (_) {}
  candidates.push(document);

  let menu = null;
  for (const d of candidates) {
    try {
      menu = d.getElementById('extensionsMenu')
        || d.getElementById('extensions_menu')
        || d.querySelector('#extensionsMenu')
        || d.querySelector('.extensions_block .list-group');
      if (menu) { doc = d; break; }
    } catch (_) {}
  }

  if (!menu) {
    setTimeout(injectWandMenuItem, 1000);
    return;
  }
  // Nút cũ còn sót lại (sự kiện có thể đã hết hiệu lực) → xóa đi tạo lại
  const oldBtn = doc.getElementById('bubble-avatar-wand-btn');
  if (oldBtn) oldBtn.remove();

  const mi = doc.createElement('a');
  mi.id = 'bubble-avatar-wand-btn';
  mi.className = 'list-group-item';
  mi.href = 'javascript:void(0)';
  mi.innerHTML = '<span class="fa-solid fa-comments"></span> Bong bóng thoại';
  mi.addEventListener('click', (e) => {
    e.preventDefault(); e.stopPropagation();
    avatarManagerPanel.open().catch(err => {
      console.error('[BubbleDialogue] open() thất bại:', err);
    });
    try { menu.parentElement?.click?.(); } catch (_) {}
  });
  menu.appendChild(mi);
}

$(() => {
  // Đăng ký sự kiện nút trợ lý quán rượu (có thể chưa tải, dùng try-catch để bảo vệ)
  try {
    if (typeof eventOn === 'function' && typeof getButtonEvent === 'function') {
      eventOn(getButtonEvent('Bong bóng thoại'), () => {
        avatarManagerPanel.open().catch(err => console.error('[BubbleDialogue] open() thất bại:', err));
      });
    }
  } catch (e) {
    console.warn('[BubbleDialogue] Đăng ký sự kiện nút trợ lý quán rượu thất bại:', e);
  }

  avatarDB.init().then(() => {
    // Thực thi tiêm lần đầu ngay sau khi DB sẵn sàng
    applyInjection(avatarDB);
  }).catch((err) => {
    console.warn('[BubbleDialogue] Khởi tạo DB thất bại:', err);
  });

  injectWandMenuItem();
  // v7.0: Định kỳ tiêm lại nút đũa phép (sự kiện nút cũ sẽ hết hiệu lực khi menu quán rượu được xây dựng lại hoặc script tải lại nóng)
  setInterval(injectWandMenuItem, 5000);

  // Lắng nghe sự kiện chuyển đổi trò chuyện, tiêm lại (tiêm injectPrompts chỉ có hiệu lực trong trò chuyện hiện tại)
  try {
    if (typeof tavern_events !== 'undefined' && tavern_events.CHAT_CHANGED) {
      eventOn(tavern_events.CHAT_CHANGED, () => {
        invalidateInjectionCache();
        applyInjection(avatarDB);
      });
    }
  } catch (e) {
    console.warn('[BubbleDialogue] Không thể lắng nghe sự kiện CHAT_CHANGED:', e);
  }
});
